// Gerar notificações para cada endpoint com SLA violado
const violations = $input.all().filter(i => i.json.sla_status && i.json.mensagem);

for (const v of violations) {
  const evento = v.json.sla_status === 'erro' ? 'sync_falhou' : 'sync_atrasado';

  // Enfileirar via RPC
  await $http.request({
    method: 'POST',
    url: `${$env.SUPABASE_URL}/rest/v1/rpc/fn_enfileirar_notificacao`,
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      p_evento: evento,
      p_titulo: `SLA ${v.json.sla_status.toUpperCase()}: ${v.json.endpoint_nome}`,
      p_mensagem: v.json.mensagem,
      p_dados: JSON.stringify(v.json)
    }
  });
}

return [{ json: { sla_violacoes: violations.length } }];

// Marcar como 'enviando' e preparar payload por tipo de canal
const items = $input.all();
const results = [];

for (const item of items) {
  const notif = item.json;
  const canal = notif.canal;

  if (!canal) continue;

  // Marcar como enviando
  await $http.request({
    method: 'PATCH',
    url: `${$env.SUPABASE_URL}/rest/v1/cq_fila_notificacao?id=eq.${notif.id}`,
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json'
    },
    body: { status: 'enviando', tentativas: (notif.tentativas || 0) + 1 }
  });

  results.push({
    json: {
      fila_id: notif.id,
      canal_tipo: canal.tipo,
      canal_config: canal.config_json,
      titulo: notif.titulo,
      mensagem: notif.mensagem,
      evento: notif.evento,
      dados: notif.dados_json,
      tentativas: (notif.tentativas || 0) + 1,
      max_tentativas: notif.max_tentativas || 3
    }
  });
}

return results;

// Registrar resultado do envio e atualizar fila
const items = $input.all();

for (const item of items) {
  const filaId = item.json.fila_id || item.json._fila_id;
  const sucesso = !item.json.error;
  const statusHttp = item.json.statusCode || 200;

  // Atualizar fila
  const novoStatus = sucesso ? 'enviado' : 
    (item.json.tentativas >= item.json.max_tentativas ? 'erro' : 'pendente');

  await $http.request({
    method: 'PATCH',
    url: `${$env.SUPABASE_URL}/rest/v1/cq_fila_notificacao?id=eq.${filaId}`,
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      status: novoStatus,
      enviado_em: sucesso ? new Date().toISOString() : null,
      erro_msg: sucesso ? null : (item.json.error || 'Falha no envio')
    }
  });

  // Registrar no log
  await $http.request({
    method: 'POST',
    url: `${$env.SUPABASE_URL}/rest/v1/cq_notificacao_log`,
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      fila_id: filaId,
      canal_tipo: item.json.canal_tipo,
      evento: item.json.evento,
      titulo: item.json.titulo,
      mensagem: item.json.mensagem,
      status_http: statusHttp,
      sucesso: sucesso
    }
  });
}

return [{ json: { processados: items.length } }];
